### Description

Since Orval 8, propertyNames enum generate invalid typescript

```ts
export type MyClassData = {[key: 'key1' | 'key2']: boolean};
```

```
TS1337: An index signature parameter type cannot be a literal type or generic type. Consider using a mapped object type instead.
```

### OpenAPI document (minimal, if applicable)

```json
{
  "openapi": "3.1.0",
  "info": {
    "title": "My app",
    "version": "TEST_VERSION"
  },
  "paths": {
    "/": {
      "get": {
        "summary": "Root",
        "operationId": "root",
        "responses": {
          "200": {
            "description": "Successful Response",
            "content": {
              "application/json": {
                "schema": {
                  "$ref": "#/components/schemas/MyClass"
                }
              }
            }
          }
        }
      }
    }
  },
  "components": {
    "schemas": {
      "MyClass": {
        "properties": {
          "data": {
            "additionalProperties": {
              "type": "boolean"
            },
            "propertyNames": {
              "enum": [
                "key1",
                "key2"
              ]
            },
            "type": "object",
            "title": "Data"
          }
        },
        "type": "object",
        "required": [
          "data"
        ]
      }
    }
  }
}
```

